import{_ as o,a as e,b as t}from"./chunks/koishi-onebot-setting.CwPzdrkF.js";import{_ as a,c as s,o as c,a1 as i}from"./chunks/framework.B7NcDNB9.js";const T=JSON.parse('{"title":"接入框架","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/integration.md","filePath":"zh-CN/guide/integration.md","lastUpdated":1718371299000}'),l={name:"zh-CN/guide/integration.md"},d=i('<h1 id="接入框架" tabindex="-1">接入框架 <a class="header-anchor" href="#接入框架" aria-label="Permalink to &quot;接入框架&quot;">​</a></h1><h2 id="对接开源框架" tabindex="-1">对接开源框架 <a class="header-anchor" href="#对接开源框架" aria-label="Permalink to &quot;对接开源框架&quot;">​</a></h2><details class="details custom-block"><summary>配置 NoneBot</summary><ol><li><p>配置 NoneBot</p><p>这里假设你已经安装了 OneBot 适配器</p><p>默认情况下，NoneBot 是启用了反向 ws 的，如果出现 403，可能是默认配置问题，需要配置 <code>token</code> 才能正常连接。具体方法为：修改 NoneBot 配置文件 <code>.env</code>，添加 <code>ONEBOT_ACCESS_TOKEN=你在 NapCat 中配置的 token</code>。</p><p>然后，启动 NoneBot，可以看到 NoneBot 输出的端口号，如 <code>8080</code>。</p></li><li><p>配置 NapCat</p><p>在 NapCat 配置添加反向 ws 地址，地址为 <code>ws://127.0.0.1:8080/onebot/v11/ws</code>, 这里的 <code>8080</code> 是 NoneBot 输出的端口号，<code>/onebot/v11/ws</code> 是 NoneBot onebot 适配器默认的路径</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>时刻记得：NapCat 配置的 <code>token</code> 需要和 NoneBot 配置的一致！</p></div></li></ol></details><details class="details custom-block"><summary>配置 Koishi</summary><ol><li><p>在 Koishi 插件市场搜索 <code>onebot</code> 并安装 <code>adapter-onebot</code>，如下图：</p><p><img src="'+o+'" alt="koishi-install-onebot"></p></li><li><p>安装完之后，点击修改→配置</p><p><img src="'+e+'" alt="koishi-onebot-go-setting"></p></li><li><p>配置 OneBot</p><p>这里以 WS 反向连接为例：</p><ul><li><code>selfId</code> 为你的机器人的 QQ 号</li><li><code>token</code> 需和 NapCat 配置的 <code>token</code> 一致，当然，如果没有配置 token，则留空。</li><li>protocol 选择 ws-reverse</li></ul><p>其他配置保持默认即可，点击保存，然后启用插件。</p><p><img src="'+t+'" alt="koishi-onebot-setting"></p><p>配置完成后，在 NapCat 的配置中添加 WS 反向地址。Koishi OneBot 的 ws 反向地址为 <code>ws://127.0.0.1:5140/onebot</code>。添加完成后，点击保存即可。</p></li></ol></details><h2 id="配置-http-服务" tabindex="-1">配置 HTTP 服务 <a class="header-anchor" href="#配置-http-服务" aria-label="Permalink to &quot;配置 HTTP 服务&quot;">​</a></h2><p>HTTP 服务的配置主要有两方面：一方面是 HTTP 监听端口（应当由你的应用端来调用），另一方面是 HTTP 上报地址（由 NapCat 来调用你的应用端）。</p><details class="details custom-block"><summary>HTTP 监听端口</summary><p>例如，配置的端口号为 <code>3000</code>，那么 API 地址为 <code>http://localhost:3000</code>。</p></details><details class="details custom-block"><summary>HTTP 上报地址</summary><p>当 NapCat 收到消息等事件时，会以 <code>POST</code> 请求的方式将事件上报到此地址。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>上报地址必须是 <code>http://</code> 开头</p></div></details><h2 id="配置-websocket-服务" tabindex="-1">配置 WebSocket 服务 <a class="header-anchor" href="#配置-websocket-服务" aria-label="Permalink to &quot;配置 WebSocket 服务&quot;">​</a></h2><p>OneBot 11 标准中，对“正向 WS”“反向 WS”的定义较为模糊，这里明确如下：正向指<strong>接受</strong>应用端的 WS 连接；反向指 NapCat 主动连接应用端监听的反向 WS 地址。</p><details class="details custom-block"><summary>正向 WS 配置</summary><p>例如，配置的端口号为 <code>3001</code>，那么需要在应用端配置的 WS 地址为 <code>ws://localhost:3001</code>。</p></details><details class="details custom-block"><summary>反向 WS 配置</summary><p>例如，在 NoneBot2 配置 OneBot 的端口为 <code>8080</code>，路径为 <code>/onebot/v11/ws</code>，那么配置的反向 WS 地址为 <code>ws://localhost:8080/onebot/v11/ws</code>。</p></details>',12),p=[d];function n(r,m,h,u,_,b){return c(),s("div",null,p)}const S=a(l,[["render",n]]);export{T as __pageData,S as default};
